// SQL: ORDER BY content <@> 'database system'
// The <@> operator triggers BM25 scoring.
// bm25query can be plain text or explicit:
//   SELECT * FROM documents
//   ORDER BY content <@> 'search terms'
//   LIMIT 5;
//
// Or with explicit index:
//   SELECT * FROM documents
//   WHERE content <@> to_bm25query(
//     'search terms', 'docs_idx'
//   ) < -1.0;

// src/planner/hooks.c — Parse analysis and planner hooks
static bool
lookup_bm25_oids_internal(BM25OidCache *cache)
{
    HeapTuple tuple;
    List     *opname;

    /* Look up bm25 access method */
    tuple = SearchSysCache1(
        AMNAME, CStringGetDatum("bm25"));
    if (HeapTupleIsValid(tuple)) {
        cache->bm25_am_oid =
            ((Form_pg_am)GETSTRUCT(tuple))->oid;
        ReleaseSysCache(tuple);
    }

    /* Look up the <@> operator for (text, text) */
    opname = list_make1(makeString("<@>"));
    cache->text_text_operator_oid =
        OpernameGetOprid(opname, TEXTOID, TEXTOID);
    list_free(opname);

    return true;
}

// src/types/vector.c — to_tpvector: text -> lexemes
Datum
to_tpvector(PG_FUNCTION_ARGS)
{
    text *input_text = PG_GETARG_TEXT_PP(0);
    text *index_name_text = PG_GETARG_TEXT_PP(1);

    /* Get text config from index metapage */
    metap = tp_get_metapage(index_rel);
    text_config_oid = metap->text_config_oid;

    /* Use Postgres to_tsvector to tokenize */
    tsvector_datum = DirectFunctionCall2(
        to_tsvector_byid,
        ObjectIdGetDatum(text_config_oid),
        PointerGetDatum(input_text));
    tsvector = DatumGetTSVector(tsvector_datum);

    /* Extract lexemes and their frequencies */
    we = ARRPTR(tsvector);
    for (i = 0; i < entry_count; i++) {
        lexemes[i] = STRPTR(tsvector) + we[i].pos;
        frequencies[i] = POSDATALEN(tsvector, &we[i]);
    }

    result = create_tpvector_from_strings(
        index_name, entry_count, lexemes, frequencies);
    PG_RETURN_POINTER(result);
}

// src/query/score.c — IDF and document frequency
float4
tp_calculate_idf(int32 doc_freq, int32 total_docs)
{
    double idf_numerator =
        (double)(total_docs - doc_freq + 0.5);
    double idf_denominator =
        (double)(doc_freq + 0.5);
    double idf_ratio =
        idf_numerator / idf_denominator;
    return (float4)log(1.0 + idf_ratio);
}

/* Batch lookup across memtable + all segments */
static void
tp_batch_get_unified_doc_freq(
    TpLocalIndexState *local_state,
    Relation           index,
    char             **terms,
    int                term_count,
    BlockNumber       *level_heads,
    uint32            *doc_freqs)
{
    /* Initialize with memtable counts */
    for (i = 0; i < term_count; i++) {
        TpPostingList *pl =
            tp_get_posting_list(local_state, terms[i]);
        doc_freqs[i] = pl ? pl->doc_count : 0;
    }
    /* Add counts from all segment levels */
    for (level = 0; level < TP_MAX_LEVELS; level++)
        if (level_heads[level] != InvalidBlockNumber)
            tp_batch_get_segment_doc_freq(
                index, level_heads[level],
                terms, term_count, doc_freqs);
}

// src/memtable/scan.c — Search entry point
bool
tp_memtable_search(
    IndexScanDesc      scan,
    TpLocalIndexState *index_state,
    TpVector          *query_vector,
    TpIndexMetaPage    metap)
{
    TpScanOpaque so = (TpScanOpaque)scan->opaque;

    /* Extract terms and frequencies */
    entries_ptr = TPVECTOR_ENTRIES_PTR(query_vector);
    for (int i = 0; i < entry_count; i++) {
        TpVectorEntry *entry = (TpVectorEntry *)ptr;
        term_str = palloc(entry->lexeme_len + 1);
        memcpy(term_str, entry->lexeme,
               entry->lexeme_len);
        query_terms[i] = term_str;
        query_frequencies[i] = entry->frequency;
    }

    /* BM25 parameters from index metadata */
    k1_value = metap->k1;  // default 1.2
    b_value  = metap->b;   // default 0.75

    /* Score documents */
    result_count = tp_score_documents(
        index_state, scan->indexRelation,
        query_terms, query_frequencies,
        entry_count, k1_value, b_value,
        max_results, so->result_ctids,
        &so->result_scores);
}

// src/query/bmw.c — Block-Max WAND heap
typedef struct TpTopKHeap
{
    ItemPointerData *ctids;
    BlockNumber     *seg_blocks;
    uint32          *doc_ids;
    float4          *scores;
    int              capacity;  // k
    int              size;
} TpTopKHeap;

static inline float4
tp_topk_threshold(TpTopKHeap *heap)
{
    return (heap->size >= heap->capacity)
        ? heap->scores[0] : 0.0f;
}

static inline bool
tp_topk_dominated(TpTopKHeap *heap, float4 score)
{
    return heap->size >= heap->capacity
        && score < heap->scores[0];
}

