// src/segment/compression.c — Posting list compression
// Delta encoding + bitpacking with SSE2/NEON SIMD

static void
bitpack_decode(
    const uint8 *in, uint32 count,
    uint8 bits, uint32 *out)
{
    uint32 mask = (bits == 32)
        ? UINT32_MAX : ((1U << bits) - 1);

#if defined(TP_SIMD_SSE2)
    __m128i vmask = _mm_set1_epi32((int)mask);
    uint32 simd_end = count & ~3U;

    for (i = 0; i < simd_end; i += 4) {
        uint32 bit_off = i * (uint32)bits;
        uint64 raw;
        memcpy(&raw, in + (bit_off >> 3), 8);
        v0 = (uint32)(raw >> (bit_off & 7)) & mask;
        // ... extract v1, v2, v3 similarly

        _mm_storeu_si128(
            (__m128i *)(out + i),
            _mm_and_si128(
                _mm_setr_epi32(v0, v1, v2, v3),
                vmask));
    }
#elif defined(TP_SIMD_NEON)
    // ARM NEON vectorized path
#endif
}

// src/am/scan.c — Return ranked results to Postgres
bool
tp_gettuple(IndexScanDesc scan, ScanDirection dir)
{
    TpScanOpaque so = (TpScanOpaque)scan->opaque;

    /* Execute scoring query on first call */
    if (so->result_ctids == NULL && !so->eof_reached)
    {
        pgstat_count_index_scan(scan->indexRelation);
        if (!tp_execute_scoring_query(scan)) {
            so->eof_reached = true;
            return false;
        }
    }

    /* Return next result from sorted array */
    scan->xs_heaptid =
        so->result_ctids[so->current_pos];
    scan->xs_recheck = false;

    /* Set ORDER BY distance (negative BM25) */
    raw_score =
        so->result_scores[so->current_pos];
    bm25_score = (raw_score > 0)
        ? -raw_score : raw_score;
    scan->xs_orderbyvals[0] =
        Float4GetDatum(bm25_score);

    /* Cache for stub function */
    tp_cached_score = (float8)bm25_score;
    so->current_pos++;
    return true;
}
